@namespace sv_b997a8397bb34cd4b965155b2354c857.Components.Pages.Catalog

<div class="card h-100 product-card" @onclick="HandleCardClick" role="button">
    <div class="card-img-top bg-secondary d-flex align-items-center justify-content-center"
         style="height: 180px;"
         title="@Product.Name">
        <span class="text-white text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title text-truncate" title="@Product.Name">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2">
            <span class="text-warning">@StarRating</span>
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private string StarRating
    {
        get
        {
            int filled = (int)Math.Round(Product.Rating);
            return new string('★', filled) + new string('☆', 5 - filled);
        }
    }

    private async Task HandleCardClick() => await OnSelected.InvokeAsync(Product);

    private async Task HandleAddToCart() => await OnAddToCart.InvokeAsync(Product);
}

@namespace sv_b997a8397bb34cd4b965155b2354c857.Components.Pages.Catalog

@if (Products is null || Products.Count == 0)
{
    <div class="text-center text-muted py-5">
        <h5>No products found</h5>
        <p>Try adjusting your filters.</p>
    </div>
}
else
{
    <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@namespace sv_b997a8397bb34cd4b965155b2354c857.Components.Pages.Catalog

<div class="p-3 border rounded bg-light">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Category</label>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@(_selectedCategories.Contains(category))"
                           @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Price Range</label>
        <div class="d-flex gap-2">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@_minPrice" @onchange="e => _minPrice = ParseDecimal(e.Value)" />
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@_maxPrice" @onchange="e => _maxPrice = ParseDecimal(e.Value)" />
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   checked="@_inStockOnly"
                   @onchange="e => _inStockOnly = (bool)e.Value!" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFiltersApplied { get; set; }

    [Parameter]
    public EventCallback OnFiltersCleared { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFiltersApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFiltersCleared.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@namespace sv_b997a8397bb34cd4b965155b2354c857.Components.Pages.Catalog

<div class="d-flex justify-content-between align-items-center flex-wrap gap-2 mb-3">
    <div>
        <select class="form-select form-select-sm" style="width: auto;"
                value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <div class="text-muted small">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <span>Showing @start–@end of @TotalCount products</span>
        }
    </div>
</div>

@code {
    [Parameter] public string SortBy { get; set; } = "price_asc";
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int Page { get; set; }
    [Parameter] public int PageSize { get; set; }
    [Parameter] public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_b997a8397bb34cd4b965155b2354c857.Components.Pages.Catalog

@if (TotalPages > 1)
{
    <nav class="mt-4">
        <ul class="pagination justify-content-center">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => ChangePage(CurrentPage - 1)" disabled="@(CurrentPage <= 1)">Previous</button>
            </li>
            @for (int i = 1; i <= TotalPages; i++)
            {
                var page = i;
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="() => ChangePage(page)">@page</button>
                </li>
            }
            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => ChangePage(CurrentPage + 1)" disabled="@(CurrentPage >= TotalPages)">Next</button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int CurrentPage { get; set; }
    [Parameter] public int TotalPages { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task ChangePage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
            await OnPageChanged.InvokeAsync(page);
    }
}

@page "/catalog"
@namespace sv_b997a8397bb34cd4b965155b2354c857.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    <div class="col-lg-3 mb-3">
        <CatalogSidebar Categories="_categories"
                        OnFiltersApplied="HandleFiltersApplied"
                        OnFiltersCleared="HandleFiltersCleared" />
    </div>
    <div class="col-lg-9">
        @if (_error is not null)
        {
            <div class="alert alert-danger">
                <strong>Error:</strong> @_error
                <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <p class="mt-2 text-muted">Loading products...</p>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_totalCount"
                            Page="_currentPage"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_products"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="_currentPage"
                               TotalPages="_totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    private const int PageSize = 9;

    private List<Product> _products = [];
    private List<string>? _categories;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            _categories = categoriesTask.Result;
            ApplyResult(productsTask.Result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            ApplyResult(result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyResult(PagedResult<Product> result)
    {
        _products = result.Items;
        _totalCount = result.TotalCount;
        _currentPage = result.Page;
        _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleFiltersCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart functionality
        return Task.CompletedTask;
    }
}

